<g transform="translate(121.9,60.6) rotate(38.4)"><ellipse rx="9.16" ry="5.39" fill="#3F7E38"/></g>
<g transform="translate(67.4,64.1) rotate(-22.9)"><ellipse rx="9.65" ry="5.68" fill="#82B04F"/></g>
<g transform="translate(90.8,65.2) rotate(-53.3)"><ellipse rx="9.41" ry="5.53" fill="#3F7E38"/></g>
<g transform="translate(119.6,65.3) rotate(59.6)"><ellipse rx="9.03" ry="5.31" fill="#82B04F"/></g>
<g transform="translate(64.2,68.6) rotate(56.8)"><ellipse rx="9.68" ry="5.69" fill="#82B04F"/></g>
<g transform="translate(65.1,69.7) rotate(-49.6)"><ellipse rx="10.16" ry="5.98" fill="#82B04F"/></g>
<g transform="translate(111.4,78.2) rotate(17.6)"><ellipse rx="9.24" ry="5.44" fill="#82B04F"/></g>
<g transform="translate(91.6,84.0) rotate(42.2)"><ellipse rx="9.21" ry="5.42" fill="#82B04F"/></g>`;
const PERSON = (fill, leaf) => `<g fill="${fill}">
  <circle cx="100" cy="86" r="7.6"/>
  <path d="M100 94 C 94 94, 90.5 98, 90.5 103 C 90.5 107, 93 110, 94.5 114 C 90 119, 84 122, 78 123 C 82 128, 89 127, 94 123 C 92 131, 90 140, 92 148 C 96 143, 99 137, 100 131 C 101 137, 104 143, 108 148 C 110 140, 108 131, 106 123 C 111 127, 118 128, 122 123 C 116 122, 110 119, 105.5 114 C 107 110, 109.5 107, 109.5 103 C 109.5 98, 106 94, 100 94 Z"/>
  <path d="M96 100 C 88 95, 82 88, 78 79 C 84 84, 91 90, 97 95 Z"/>
